import React, {useState} from "react";
import CardsCities from "./CardsCities";
import Box from '@mui/material/Box';
import TextField from '@mui/material/TextField';
import axios from "axios"
import { useEffect } from "react";


export default function SearchCities() {
    const [inputValue, setInputValue] = useState("")
    const [cities, setCities] = useState()

    useEffect(() => {
        axios.get("http://localhost:4000/api/cities")
        .then(response => setCities(response.response.cities))
    }, [])

    let Filter = cities?.filter(city => city.cityname.toLowerCase().startsWith(inputValue.toLocaleLowerCase().trim()));

    return (
    <>
        <div>
            <Box
                component="form"
                sx={{
                '& > :not(style)': { m: 1, width: '25ch' },
                }}
                noValidate
                autoComplete="off"
            >
                <TextField id="outlined-basic" label="Search cities!" variant="outlined" type={"text"} oneKeyUp={(evento) => { setInputValue(evento.target.value) }} />
            </Box>
        </div>
        <div>
            {Filter?.length > 0 ? (<CardsCities cardFilter={Filter} />) : <p>NOT FOUND</p>}
        </div>
    </>
    );
}
